// Generates public/learn/media-config.js from an env var so the self-contained /learn
// docs viewer can load big media (videos + GIFs) from a Cloudflare R2 bucket without the
// URL being hardcoded/committed. Files under public/ are served verbatim by Next and are
// NOT processed for env vars, so we materialize a tiny JS file the viewer loads at runtime.
//
// Env: NEXT_PUBLIC_LEARN_MEDIA_BASE = https://pub-<hash>.r2.dev   (no trailing slash)
// Unset/empty -> viewer falls back to serving media locally from ./media/.
//
// Runs on `predev` and `prebuild`. The generated file is gitignored.

import nextEnv from "@next/env";
import { writeFileSync } from "node:fs";
import { fileURLToPath } from "node:url";
import { dirname, join } from "node:path";

const webRoot = join(dirname(fileURLToPath(import.meta.url)), "..");
nextEnv.loadEnvConfig(webRoot); // loads .env, .env.local, etc. exactly like Next does

const base = (process.env.NEXT_PUBLIC_LEARN_MEDIA_BASE || "").trim().replace(/\/+$/, "");
const out = join(webRoot, "public", "learn", "media-config.js");

writeFileSync(
  out,
  `// AUTO-GENERATED by scripts/gen-learn-media-config.mjs — do not edit, do not commit.\n` +
    `window.LEARN_MEDIA_BASE = ${JSON.stringify(base)};\n`
);

console.log(`[learn] media base -> ${base || "(local ./media/)"}`);
